#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include <stdbool.h>
#include <unistd.h>
#include <errno.h>
#include <fcntl.h>
#include <sys/stat.h>
#include <sys/mman.h>
#include <ctype.h>
#include "blake3.h"

#define READ_BUF 65536

typedef struct {
    bool keyed;
    bool derive_key;
    char *derive_key_value;
    bool length_set;
    uint64_t length;
    bool seek_set;
    uint64_t seek;
    bool num_threads_set;
    int64_t num_threads;
    bool no_mmap;
    bool no_names;
    bool raw;
    bool tag;
    bool check;
    bool quiet;
    char **files;
    int num_files;
} options_t;

