    fprintf(stderr, "\n  tip: to pass '%s' as a value, use '-- %s'\n", arg, arg);
    fputc('\n', stderr);
    clap_print_usage(stderr, "[OPTIONS] [FILE]...");
    clap_print_for_more(stderr);
    exit(2);
}

