    bool derive_key;
    char *derive_key_value;
    bool length_set;
    uint64_t length;
    bool seek_set;
    uint64_t seek;
    bool num_threads_set;
    int64_t num_threads;
    bool no_mmap;
    bool no_names;
    bool raw;
    bool tag;
    bool check;
    bool quiet;
    char **files;
    int num_files;
} options_t;

